can clamp(value: int, low: int, high: int) -> int {
    if value < low {
        return low;
    }
    if value > high {
        return high;
    }
    return value;
}

can normalize_scores(scores: list[int]) -> list[int] {
    normalized: list[int] = [];
    for score in scores {
        normalized.append(clamp(score, 0, 100));
    }
    return normalized;
}

