node Page {
    has path: str;
    has visits: int = 0;

    can record_visit {
        self.visits += 1;
    }
}

edge Link {
    has label: str = "link";
}

walker VisitCounter {
    has total: int = 0;

    can root entry {
        visit [-->];
    }

    can Page entry {
        here.record_visit();
        self.total += here.visits;
        visit [-->];
    }
}

with entry {
    home = root ++> node::Page(path="/");
    docs = home +:edge::Link(label="docs"):+> node::Page(path="/docs");
    api = docs +:edge::Link(label="api"):+> node::Page(path="/docs/api");
    root spawn VisitCounter();
}

can count_success(statuses: list[int]) -> int {
    successes: int = 0;
    for status in statuses {
        if status >= 200 and status < 300 {
            successes += 1;
        }
    }
    return successes;
}

can count_client_errors(statuses: list[int]) -> int {
    errors: int = 0;
    for status in statuses {
        if status >= 400 and status < 500 {
            errors += 1;
        }
    }
    return errors;
}

can success_rate_percent(statuses: list[int]) -> float {
    if len(statuses) == 0 {
        return 0.0;
    }
    return (count_success(statuses) * 100.0) / len(statuses);
}

with entry {
    response_codes: list[int] = [200, 201, 204, 301, 404, 429, 500, 200];
    print(count_success(response_codes));
    print(count_client_errors(response_codes));
    print(success_rate_percent(response_codes));
}

node Task {
    has name: str;
    has cost: int;
    has done: bool = False;
}

edge DependsOn {
    has required: bool = True;
}

walker CostPlanner {
    has total_cost: int = 0;
    has completed: int = 0;

    can root entry {
        visit [-->];
    }

    can Task entry {
        if here.done == False {
            here.done = True;
            self.total_cost += here.cost;
            self.completed += 1;
            visit [-->];
        }
    }
}

with entry {
    design = root ++> node::Task(name="design", cost=3);
    build = design +:edge::DependsOn(required=True):+> node::Task(name="build", cost=8);
    test = build +:edge::DependsOn(required=True):+> node::Task(name="test", cost=5);
    deploy = test +:edge::DependsOn(required=True):+> node::Task(name="deploy", cost=2);
    root spawn CostPlanner();
}
